from dataclasses import dataclass
from typing import Callable
from langchain_openai import ChatOpenAI
from langchain_core.prompts import ChatPromptTemplate
from langchain_core.output_parsers import StrOutputParser

llm = ChatOpenAI(model="gpt-4o-mini", temperature=0)
parser = StrOutputParser()

@dataclass
class Worker:
    name: str
    description: str
    fn: Callable[[str], str]   # takes instruction string, returns result string

# ── Define specialised workers ───────────────────────────────────────────────

def research_worker(instruction: str) -> str:
    chain = (
        ChatPromptTemplate.from_messages([
            ("system", "You are a research assistant. Find and summarise relevant facts."),
            ("human", "{instruction}"),
        ]) | llm | parser
    )
    return chain.invoke({"instruction": instruction})

def code_worker(instruction: str) -> str:
    chain = (
        ChatPromptTemplate.from_messages([
            ("system", "You are a software engineer. Write clean, runnable Python code."),
            ("human", "{instruction}"),
        ]) | llm | parser
    )
    return chain.invoke({"instruction": instruction})

def critique_worker(instruction: str) -> str:
    chain = (
        ChatPromptTemplate.from_messages([
            ("system", "You are a critical reviewer. Identify flaws and suggest improvements."),
            ("human", "{instruction}"),
        ]) | llm | parser
    )
    return chain.invoke({"instruction": instruction})

def math_worker(instruction: str) -> str:
    chain = (
        ChatPromptTemplate.from_messages([
            ("system", "You are a mathematician. Solve calculations step by step."),
            ("human", "{instruction}"),
        ]) | llm | parser
    )
    return chain.invoke({"instruction": instruction})

WORKERS: dict[str, Worker] = {
    w.name: w for w in [
        Worker("research",  "Finds facts, summaries, and background information", research_worker),
        Worker("code",      "Writes Python code to solve a specific problem",      code_worker),
        Worker("critique",  "Reviews and critiques text, code, or plans",          critique_worker),
        Worker("math",      "Performs mathematical calculations and reasoning",     math_worker),
    ]
}

def orchestrate(objective: str, max_steps: int = 10, verbose: bool = True) -> str:
    history_entries: list[str] = []

    for step in range(max_steps):
        history = "\n".join(history_entries) if history_entries else "(none yet)"

        decision = orchestrator_chain.invoke({
            "objective": objective,
            "history": history,
        })

        if verbose:
            print(f"[Step {step+1}] action={decision.action} reason={decision.reasoning[:60]}")

        if decision.action == "finish":
            return decision.final_answer or "[no answer provided]"

        if decision.action == "delegate":
            worker_name = decision.worker_name
            instruction = decision.instruction

            worker = WORKERS.get(worker_name)
            if worker is None:
                history_entries.append(
                    f"Step {step+1}: tried to call unknown worker '{worker_name}' — skipped"
                )
                continue

            if verbose:
                print(f"         → calling '{worker_name}': {instruction[:80]}")

            result = worker.fn(instruction)
            history_entries.append(
                f"Step {step+1} [{worker_name}]\n"
                f"Instruction: {instruction}\n"
                f"Result: {result}"
            )

    # Max steps reached — ask orchestrator to synthesise what it has
    history = "\n".join(history_entries)
    fallback = orchestrator_chain.invoke({
        "objective": f"Summarise the work done so far for: {objective}",
        "history": history,
    })
    return fallback.final_answer or "[max steps reached, partial result in history]"

# Example
result = orchestrate(
    "Research the pros and cons of vector databases vs relational databases for AI applications, "
    "then write a Python function that decides which to use based on query patterns.",
    max_steps=8,
)
print(result)

from typing import TypedDict, Annotated
from langgraph.graph import StateGraph, END
import operator

class OrchestratorState(TypedDict):
    objective: str
    history: Annotated[list[str], operator.add]  # append-only list
    final_answer: str
    step: int

def orchestrator_node(state: OrchestratorState) -> OrchestratorState:
    decision = orchestrator_chain.invoke({
        "objective": state["objective"],
        "history": "\n".join(state["history"]) or "(none yet)",
    })

    if decision.action == "finish":
        return {**state, "final_answer": decision.final_answer or "", "step": state["step"] + 1}

    # Store decision for routing
    return {
        **state,
        "history": [f"_NEXT: {decision.worker_name}|{decision.instruction}"],
        "step": state["step"] + 1,
    }

def make_worker_node(worker: Worker):
    def node(state: OrchestratorState) -> OrchestratorState:
        # Extract instruction from the last history entry
        last = state["history"][-1]
        instruction = last.split("|", 1)[1] if "|" in last else last
        result = worker.fn(instruction)
        return {
            **state,
            "history": [f"[{worker.name}] {instruction[:60]}... → {result[:200]}"],
        }
    node.__name__ = worker.name
    return node

def route_to_worker(state: OrchestratorState) -> str:
    if state["final_answer"]:
        return END
    if state["step"] >= 10:
        return END
    last = state["history"][-1] if state["history"] else ""
    if last.startswith("_NEXT:"):
        worker_name = last[6:].split("|")[0]
        return worker_name if worker_name in WORKERS else END
    return END

graph = StateGraph(OrchestratorState)
graph.add_node("orchestrator", orchestrator_node)
for name, worker in WORKERS.items():
    graph.add_node(name, make_worker_node(worker))
    graph.add_edge(name, "orchestrator")

graph.set_entry_point("orchestrator")
graph.add_conditional_edges(
    "orchestrator",
    route_to_worker,
    {name: name for name in WORKERS} | {END: END},
)
app = graph.compile()

import time
from typing import Optional

WORKER_FALLBACKS: dict[str, str] = {
    "research": "critique",   # if research fails, ask critique to work with what it knows
    "code": "research",        # if code fails, research the approach first
}

def dispatch_with_retry(
    worker_name: str,
    instruction: str,
    max_attempts: int = 3,
    base_delay: float = 1.0,
) -> str:
    """Call a worker with exponential backoff retry and fallback."""
    last_error: Optional[Exception] = None

    for attempt in range(max_attempts):
        worker = WORKERS.get(worker_name)
        if worker is None:
            break
        try:
            result = worker.fn(instruction)
            if result and len(result.strip()) > 10:
                return result
            # Empty result — treat as failure
            raise ValueError(f"Worker returned empty result (attempt {attempt+1})")
        except Exception as e:
            last_error = e
            if attempt < max_attempts - 1:
                delay = base_delay * (2 ** attempt)
                time.sleep(delay)

    # Try fallback worker
    fallback_name = WORKER_FALLBACKS.get(worker_name)
    if fallback_name and fallback_name in WORKERS:
        try:
            fallback_result = WORKERS[fallback_name].fn(
                f"[Fallback for failed {worker_name}] {instruction}"
            )
            return f"[via fallback {fallback_name}] {fallback_result}"
        except Exception:
            pass

    return f"[Worker '{worker_name}' failed after {max_attempts} attempts: {last_error}]"

